# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
import logging

app = Flask(__name__)
es = Elasticsearch([{'host': 'localhost', 'port': 9200}])

@app.route('/api/search', methods=['GET'])
def search_products():
    try:
        query = request.args.get('q', '')
        if not query:
            return jsonify({'error': 'Query parameter q is required'}), 400
        
        search_body = {
            "query": {
                "multi_match": {
                    "query": query,
                    "type": "bool_prefix",
                    "fields": ["name", "description", "tags"],
                    "boost": 2,
                    "fuzziness": "AUTO"
                }
            },
            "size": 50,
            "highlight": {
                "fields": {
                    "name": {},
                    "description": {}
                }
            }
        }
        
        response = es.search(index="products", body=search_body)
        
        products = []
        for hit in response['hits']['hits']:
            product = {
                'id': hit['_id'],
                'name': hit['_source'].get('name', ''),
                'description': hit['_source'].get('description', ''),
                'price': hit['_source'].get('price', 0),
                'tags': hit['_source'].get('tags', []),
                'highlight': hit.get('highlight', {})
            }
            products.append(product)
        
        return jsonify({
            'query': query,
            'total': response['hits']['total']['value'],
            'products': products
        })
        
    except Exception as e:
        logging.error(f"Search error: {str(e)}")
        return jsonify({'error': 'Search failed'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, threaded=True)